-    // TODO: Port full algorithm from rs-bpe
-    _ = split_table;
-    _ = token1;
-    _ = token2;
-    return true;
+    var token1 = token1_arg;
+    var token2 = token2_arg;
+    var limit: u32 = std.math.maxInt(u32);
+
+    while (true) {
+        // Check if this pair exists in pair_lookup
+        if (pair_lookup.get(Pair{ .left = token1, .right = token2 })) |combined| {
+            if (combined < limit) {
+                return false;
+            }
+            return true;
+        }
+
+        if (token1 > token2) {
+            limit = token1;
+            if (split_table.get(token1)) |split| {
+                token1 = split.right;
+                if (token1 == limit) {
+                    limit = token2 + 1;
+                    if (split_table.get(token2)) |split2| {
+                        token2 = split2.left;
+                        if (token2 + 1 == limit) {
+                            return true;
+                        }
+                    } else {
+                        return true;
+                    }
+                }
+            } else {
+                return true;
+            }
+        } else {
+            limit = token2 + 1;
+            if (split_table.get(token2)) |split| {
+                token2 = split.left;
+                if (token2 + 1 == limit) {
+                    limit = token1;
+                    if (split_table.get(token1)) |split2| {
+                        token1 = split2.right;
+                        if (token1 == limit) {
+                            return true;
+                        }
+                    } else {
+                        return true;
+                    }
+                }
+            } else {
+                return true;
+            }
+        }
+    }
 }

